create extension if not exists pgcrypto;
create table if not exists invited_users(id uuid primary key default gen_random_uuid(),display_name text not null,normalized_name text unique not null,password_hash text not null,role text not null default 'guest',created_at timestamptz not null default now());
insert into invited_users(display_name,normalized_name,password_hash,role) values('Nicolly','nicolly',crypt('ni123',gen_salt('bf')),'guest'),('Joana','joana',crypt('jo456',gen_salt('bf')),'guest'),('Bianca','bianca',crypt('bi789',gen_salt('bf')),'guest'),('Marina','marina',crypt('ma012',gen_salt('bf')),'guest'),('João','joao',crypt('121225',gen_salt('bf')),'admin') on conflict(normalized_name) do nothing;
create or replace function verify_tge_guest_login(p_name text,p_password text) returns table(user_id uuid,display_name text,role text) language sql security definer as $$ select id,display_name,role from invited_users where normalized_name=p_name and password_hash=crypt(p_password,password_hash) limit 1; $$;
create table if not exists tge_questions(id uuid primary key default gen_random_uuid(),subject text not null default 'TGE',topic text,kind text not null check(kind in('closed','open')),difficulty text default 'media',prompt text not null,expected_answer text,rubric text,active boolean not null default true,created_at timestamptz not null default now());
create table if not exists tge_options(id uuid primary key default gen_random_uuid(),question_id uuid not null references tge_questions(id) on delete cascade,text text not null,is_correct boolean not null default false);
create table if not exists tge_attempts(id uuid primary key default gen_random_uuid(),user_id uuid references invited_users(id),mode text not null,has_open_questions boolean not null default false,status text not null default 'in_progress',score numeric,coefficient numeric,total_time_ms integer,started_at timestamptz not null default now(),finished_at timestamptz);
create table if not exists tge_attempt_questions(id uuid primary key default gen_random_uuid(),attempt_id uuid not null references tge_attempts(id) on delete cascade,question_id uuid not null references tge_questions(id),order_index integer not null,kind text not null,status text not null default 'draft',selected_option_id uuid,answer_text text,is_correct boolean,closed_score numeric,open_score numeric,ai_comment text,ai_status text,time_ms integer default 0);
create table if not exists chat_messages(id uuid primary key default gen_random_uuid(),user_id uuid not null references invited_users(id),body text not null,created_at timestamptz not null default now());
create table if not exists chat_reads(message_id uuid not null references chat_messages(id) on delete cascade,user_id uuid not null references invited_users(id),read_at timestamptz not null default now(),primary key(message_id,user_id));
create table if not exists ai_provider_logs(id uuid primary key default gen_random_uuid(),provider_name text not null,status text not null,message text,attempt_id uuid,created_at timestamptz not null default now());
alter table invited_users enable row level security;alter table tge_questions enable row level security;alter table tge_options enable row level security;alter table tge_attempts enable row level security;alter table tge_attempt_questions enable row level security;alter table chat_messages enable row level security;alter table chat_reads enable row level security;alter table ai_provider_logs enable row level security;